CREATE PROC [dbo].[CREATE_DOCS] @FromDate datetime, @ToDate datetime AS IF OBJECT_ID('dbo.[DOCS]','U') IS NOT NULL DROP TABLE [DOCS] IF OBJECT_ID('dbo.[DOCS_Info]','U') IS NOT NULL DROP TABLE [DOCS_Info] Select A.[Nature  of Document],A.[Sr. No. From],A.[Sr. No. To],A.[Total Number],Isnull(B.[Cancelled],0) as [Cancelled]  INTO DOCS from (select trntype, DocNoPrefix, CASE   WHEN TrnType = 2100 THEN 'Invoice for outward supply'   WHEN TrnType = 2200 THEN 'Invoice for outward supply' WHEN TrnType = 1300 THEN 'Credit Note' WHEN TrnType = 2300 THEN 'Debit Note' else Cast(TrnType as Varchar(50)) END  as [Nature  of Document]  ,DocNoPrefix +'/'+ Cast(Min(Docno) as Varchar(10)) [Sr. No. From] ,DocNoPrefix +'/'+ Cast(Max(Docno) as Varchar(10)) [Sr. No. To],count(*) as [Total Number] from stktrnhdr where trntype in (2100,2200,2300,1300) and  (docdt >= @FromDate and docdt <= @ToDate)  group by TrnType,DocNoPrefix) as A Full join (select trntype, DocNoPrefix, count(*) as [Cancelled] from stktrnhdr where trntype in (2100,2200,2300,1300) and docvoidInd = 1  and  (docdt >= @FromDate and docdt <= @ToDate) group by TrnType,DocNoPrefix) B on A.Trntype = B.TrnType  and A.DocNoPrefix = B.DocNoPrefix SELECT SUM([Total Number]) AS [Total Number],SUM([Cancelled]) AS [Total Cancelled]  INTO DOCS_Info FROM DOCS INSERT INTO InfoTable Values('DOCS',2,'<<Default>>','Docs',11) 